### 10. **Component Structure Pattern**

All components follow this structure:

```typescript
"use client"

import * as React from "react"
import { PrimitiveComponent } from "radix-ui"
import { cn } from "@/registry/bases/radix/lib/utils"

// Optional: CVA variants
const variants = cva(...)

// Root component
function Component({ className, ...props }) {
  return (
    <PrimitiveComponent.Root
      data-slot="component"
      className={cn("cn-component ...", className)}
      {...props}
    />
  )
}

// Sub-components
function ComponentSub({ className, ...props }) {
  return (
    <PrimitiveComponent.Sub
      data-slot="component-sub"
      className={cn("cn-component-sub", className)}
      {...props}
    />
  )
}

// Named exports (NOT namespaced)
export { Component, ComponentSub }
```

