function StepperHorizontal() {
  const steps = [
    { value: "account", label: "Account" },
    { value: "profile", label: "Profile" },
    { value: "review", label: "Review" },
  ]
  const [activeStep, setActiveStep] = React.useState("account")
  const currentIndex = steps.findIndex((s) => s.value === activeStep)

  return (
    <Example title="Horizontal">
      <div className="flex w-full flex-col gap-6">
        <Stepper value={activeStep} onValueChange={setActiveStep}>
          {steps.map((step, index) => (
            <StepperItem key={step.value} value={step.value}>
              <StepperTrigger>
                <StepIndicator
                  index={index + 1}
                  state={
                    step.value === activeStep
                      ? "active"
                      : currentIndex > index
                        ? "completed"
                        : "inactive"
                  }
                />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </Stepper>
        <div className="flex gap-2">
          <Button
            variant="outline"
            size="sm"
            disabled={currentIndex === 0}
            onClick={() => setActiveStep(steps[currentIndex - 1].value)}
          >
            Previous
          </Button>
          <Button
            size="sm"
            disabled={currentIndex === steps.length - 1}
            onClick={() => setActiveStep(steps[currentIndex + 1].value)}
          >
            Next
          </Button>
        </div>
      </div>
    </Example>
  )
}

