function StepperWithContent() {
  const steps = [
    { value: "account", label: "Account" },
    { value: "profile", label: "Profile" },
    { value: "payment", label: "Payment" },
    { value: "confirm", label: "Confirm" },
  ]
  const [activeStep, setActiveStep] = React.useState("account")
  const currentIndex = steps.findIndex((s) => s.value === activeStep)

  return (
    <Example title="With Content" containerClassName="lg:col-span-full">
      <div className="flex w-full flex-col gap-6">
        <Stepper
          value={activeStep}
          onValueChange={setActiveStep}
          orientation="vertical"
        >
          {steps.map((step, index) => (
            <StepperItem
              key={step.value}
              value={step.value}
              completed={currentIndex > index}
            >
              <StepperTrigger>
                <StepIndicator
                  index={index + 1}
                  state={
                    step.value === activeStep
                      ? "active"
                      : currentIndex > index
                        ? "completed"
                        : "inactive"
                  }
                />
                <StepperTitle>{step.label}</StepperTitle>
              </StepperTrigger>
              {index < steps.length - 1 && <StepperSeparator />}
              <StepperPanel>
                <div className="rounded-lg border bg-card p-4 text-sm text-muted-foreground">
                  {step.value === "account" && (
                    <p>Enter your email and create a password.</p>
                  )}
                  {step.value === "profile" && (
                    <p>Tell us your name and upload a photo.</p>
                  )}
                  {step.value === "payment" && (
                    <p>Add a payment method for your subscription.</p>
                  )}
                  {step.value === "confirm" && (
                    <p>Review your details and submit.</p>
                  )}
                </div>
                <div className="mt-4 flex gap-2">
                  {currentIndex > 0 && (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() =>
                        setActiveStep(steps[currentIndex - 1].value)
                      }
                    >
                      Back
                    </Button>
                  )}
                  {currentIndex < steps.length - 1 ? (
                    <Button
                      size="sm"
                      onClick={() =>
                        setActiveStep(steps[currentIndex + 1].value)
                      }
                    >
                      Continue
                    </Button>
                  ) : (
                    <Button size="sm">Submit</Button>
                  )}
                </div>
              </StepperPanel>
            </StepperItem>
          ))}
        </Stepper>
      </div>
    </Example>
  )
}

