"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepState = "active" | "completed" | "inactive"

// ─── Contexts ────────────────────────────────────────────────────────────────

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextValue = {
  step: number
  state: StepState
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ─────────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  /** The controlled active step (1-based). */
  value?: number
  /** The default active step when uncontrolled (1-based). */
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: controlledValue,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : internalValue

  const handleValueChange = React.useCallback(
    (next: number) => {
      if (!isControlled) setInternalValue(next)
      onValueChange?.(next)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The 1-based index of this step. */
  step: number
  /** Force this step into the "completed" state regardless of the active value. */
  completed?: boolean
  /** Prevent the trigger from being clicked. */
  disabled?: boolean
}

function StepperItem({
  step,
  completed: completedProp = false,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value } = useStepper()

  const state: StepState =
    step === value
      ? "active"
      : completedProp || step < value
        ? "completed"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled || undefined}
        className={cn(
          // Two-column grid: col-1 = indicator track, col-2 = content area.
          // The same grid is reused for both orientations; sub-components
          // declare their own row/col positions via group-data selectors.
          "group/stepper-item grid grid-cols-[auto_1fr] items-start",
          // In horizontal mode the item takes equal share of the stepper width.
          "group-data-[orientation=horizontal]/stepper:flex-1",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      aria-current={state === "active" ? "step" : undefined}
      disabled={disabled}
      onClick={() => onValueChange(step)}
      className={cn(
        // Grid position: indicator cell — col 1, row 1 in both orientations.
        "col-start-1 row-start-1",
        "focus-visible:ring-ring/50 inline-flex size-6 shrink-0 cursor-pointer items-center justify-center rounded-full text-xs font-semibold transition-colors outline-none focus-visible:ring-[3px]",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=inactive]:bg-muted data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        // Horizontal: full-width row below the indicator track, centered.
        "group-data-[orientation=horizontal]/stepper:col-start-1 group-data-[orientation=horizontal]/stepper:col-span-2 group-data-[orientation=horizontal]/stepper:row-start-2 group-data-[orientation=horizontal]/stepper:mt-2 group-data-[orientation=horizontal]/stepper:text-center",
        // Vertical: content column, same row as the trigger.
        "group-data-[orientation=vertical]/stepper:col-start-2 group-data-[orientation=vertical]/stepper:row-start-1 group-data-[orientation=vertical]/stepper:pl-3 group-data-[orientation=vertical]/stepper:pt-0.5",
        "data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-muted-foreground text-xs",
        // Horizontal: full-width row below the title, centered.
        "group-data-[orientation=horizontal]/stepper:col-start-1 group-data-[orientation=horizontal]/stepper:col-span-2 group-data-[orientation=horizontal]/stepper:row-start-3 group-data-[orientation=horizontal]/stepper:mt-1 group-data-[orientation=horizontal]/stepper:text-center",
        // Vertical: content column, row below the trigger/title row.
        "group-data-[orientation=vertical]/stepper:col-start-2 group-data-[orientation=vertical]/stepper:row-start-2 group-data-[orientation=vertical]/stepper:pl-3 group-data-[orientation=vertical]/stepper:pt-1 group-data-[orientation=vertical]/stepper:pb-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      aria-hidden
      data-slot="stepper-separator"
      data-state={state}
      className={cn(
        "bg-border transition-colors data-[state=completed]:bg-primary",
        // Horizontal: col 2, row 1 — a 1-px horizontal connector line.
        "group-data-[orientation=horizontal]/stepper:col-start-2 group-data-[orientation=horizontal]/stepper:row-start-1 group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:self-center group-data-[orientation=horizontal]/stepper:ms-1",
        // Vertical: col 1, rows 2+ — a 1-px vertical connector line.
        // ms-[11px] aligns the centre of the line with the centre of the
        // size-6 (24 px) trigger circle.  row-span-[100] lets it grow
        // through all subsequent auto-height content rows without knowing
        // how many there are.
        "group-data-[orientation=vertical]/stepper:col-start-1 group-data-[orientation=vertical]/stepper:row-start-2 group-data-[orientation=vertical]/stepper:row-span-[100] group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:min-h-4 group-data-[orientation=vertical]/stepper:self-stretch group-data-[orientation=vertical]/stepper:ms-[11px]",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

function StepperPanel({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-panel"
      className={cn(
        // Horizontal: full-width row below title/description.
        "group-data-[orientation=horizontal]/stepper:col-start-1 group-data-[orientation=horizontal]/stepper:col-span-2 group-data-[orientation=horizontal]/stepper:row-start-4 group-data-[orientation=horizontal]/stepper:mt-2",
        // Vertical: content column, row below description.
        // pb-6 gives the separator line space to remain visible below the
        // last piece of panel content.
        "group-data-[orientation=vertical]/stepper:col-start-2 group-data-[orientation=vertical]/stepper:row-start-3 group-data-[orientation=vertical]/stepper:pl-3 group-data-[orientation=vertical]/stepper:pt-2 group-data-[orientation=vertical]/stepper:pb-6",
        className
      )}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}

