# Quick TypeScript syntax check - make sure no obvious issues
node --input-type=module <<'EOF'
import { readFileSync } from 'fs'
const files = [
  '/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775494026976-effh53/apps/v4/registry/bases/base/ui/stepper.tsx',
  '/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775494026976-effh53/apps/v4/registry/bases/base/examples/stepper-example.tsx',
]
for (const f of files) {
  const src = readFileSync(f, 'utf8')
  // check exports
  const exps = src.match(/^export \{[^}]+\}/m)
  console.log(f.split('/').pop(), '→', exps ? exps[0].slice(0, 80) : '(no named export block)')
  // check balanced braces
  let depth = 0
  for (const ch of src) { if (ch === '{') depth++; else if (ch === '}') depth-- }
  console.log('  brace balance:', depth === 0 ? 'OK' : `UNBALANCED (${depth})`)
}
EOF
